return [{
  json: {
    requestSource: 'slack',
    user: {
      name: 'John Executive',
      email: 'john@company.com',
      role: 'VP Sales'
    },
    naturalLanguageRequest: 'Schedule a meeting with Acme Corp next week to discuss the Q1 proposal, and book me a flight to SF for the day before. Also send them a calendar invite and prepare a brief agenda.',
    detectedApps: ['gmail', 'calendar', 'slack', 'expensify', 'salesforce']
  }
}];

const req = $input.first().json;

// Narada's LLMCompiler parses natural language into action plan
const actionPlan = {
  steps: [
    {
      step: 1,
      app: 'salesforce',
      action: 'lookup_contact',
      params: { company: 'Acme Corp' },
      reasoning: 'Find Acme Corp contact details in CRM'
    },
    {
      step: 2,
      app: 'calendar',
      action: 'check_availability',
      params: { user: req.user.email, timeframe: 'next_week' },
      reasoning: 'Find available slots next week'
    },
    {
      step: 3,
      app: 'travel_booking',
      action: 'search_flights',
      params: { destination: 'SFO', date: 'day_before_meeting' },
      reasoning: 'Book flight to SF day before meeting'
    },
    {
      step: 4,
      app: 'calendar',
      action: 'create_event',
      params: { title: 'Q1 Proposal Discussion - Acme Corp', attendees: ['acme@contact.com'] },
      reasoning: 'Create calendar invite with prospect'
    },
    {
      step: 5,
      app: 'slack',
      action: 'notify_user',
      params: { message: 'Meeting scheduled, flight booked, agenda prepared' },
      reasoning: 'Confirm completion to user'
    }
  ],
  requiresApproval: true, // Multi-step, cross-app actions need approval
  estimatedTime: '3 minutes'
};

return [{
  json: {
    ...req,
    actionPlan,
    complexity: 'high',
    appsInvolved: actionPlan.steps.map(s => s.app).filter((v, i, a) => a.indexOf(v) === i)
  }
}];

// Simulate Web Redemption - Narada navigates apps without APIs
const plan = $input.first().json;

const executionResults = plan.actionPlan.steps.map(step => {
  const results = {
    salesforce: () => ({
      contactFound: true,
      name: 'Jane Smith',
      email: 'jane.smith@acmecorp.com',
      title: 'VP Procurement',
      lastContact: '2026-02-15'
    }),
    calendar: () => ({
      availableSlots: ['2026-03-10T14:00:00', '2026-03-11T10:00:00', '2026-03-12T15:00:00'],
      selectedSlot: '2026-03-10T14:00:00'
    }),
    travel_booking: () => ({
      flights: [
        { airline: 'United', flight: 'UA123', departure: '2026-03-09T08:00', arrival: '2026-03-09T11:30', price: 420 },
        { airline: 'Delta', flight: 'DL456', departure: '2026-03-09T09:00', arrival: '2026-03-09T12:15', price: 380 }
      ],
      selected: { airline: 'United', flight: 'UA123' }
    }),
    slack: () => ({ notified: true })
  };

  return {
    step: step.step,
    app: step.app,
    action: step.action,
    result: results[step.app] ? results[step.app]() : { success: true },
    status: 'completed'
  };
});

return [{
  json: {
    ...plan,
    executionResults,
    draftEvent: {
      title: 'Q1 Proposal Discussion - Acme Corp',
      date: '2026-03-10',
      time: '14:00 PST',
      attendees: ['jane.smith@acmecorp.com'],
      location: 'Zoom (link TBD)',
      agenda: '1. Q1 proposal review\n2. Timeline discussion\n3. Next steps'
    },
    draftFlight: {
      airline: 'United',
      flight: 'UA123',
      date: '2026-03-09',
      cost: 420
    }
  }
}];

